using Microsoft.EntityFrameworkCore;

/// <summary>
/// Cosmos DB context migrated to EF Core 9.
/// Three breaking changes addressed:
/// 1. Discriminator property renamed from "Discriminator" to "$type" — preserved for existing docs
/// 2. id property no longer contains discriminator — preserved for existing docs
/// 3. Sync I/O no longer supported — all queries must use async
/// </summary>
class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: default discriminator property changed to "$type".
        // Existing documents use "Discriminator" — must explicitly configure to preserve access.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 breaking change: id no longer includes the discriminator value.
        // Existing documents have format "Session|<key>". Preserve old format.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
}

/// <summary>
/// EF Core 9 breaking change: Cosmos DB provider no longer supports synchronous I/O.
/// All calls like ToList(), SaveChanges(), First() must become async equivalents.
/// </summary>
class CosmosQueryService
{
    // BEFORE (EF Core 8 — throws in EF Core 9):
    // var sessions = db.Sessions.Where(s => s.Name == name).ToList();
    // db.SaveChanges();

    // AFTER (EF Core 9 — use async):
    async Task<List<Session>> GetSessionsAsync(CosmosDbContext db, string name)
    {
        return await db.Sessions.Where(s => s.Name == name).ToListAsync();
    }

    async Task SaveAsync(CosmosDbContext db)
    {
        await db.SaveChangesAsync();
    }
}

